### Model Diagnostics


::: {.cell}

```{.r .cell-code}
# Show diagnostics for body damage (largest segment)
m_body <- models_by_type[["body"]]
check_model(m_body, check = c("qq", "outliers", "homogeneity", "linearity"))
```

::: {.cell-output-display}
![](02_partner_comparison_files/figure-html/model-diagnostics-1.png){width=1350}
:::
:::


### Marginal Cost Effects (ggeffects)


::: {.cell layout-ncol="2"}

```{.r .cell-code}
# Severity effect on cost — body model
gg_sev  <- ggpredict(m_body, terms = "severity_score [all]")
gg_vcls <- ggpredict(m_body, terms = "vehicle_class")

plot(gg_sev) +
  labs(title = "Marginal effect of severity (Body model)",
       subtitle = "Gamma GLM — predicted cost",
       x = "Severity Score", y = "Predicted Cost (CHF)") +
  scale_y_continuous(labels = scales::label_number(prefix = "CHF ", big.mark = ",")) +
  theme_allianz()
```

::: {.cell-output-display}
![](02_partner_comparison_files/figure-html/marginal-effects-1.png){width=1350}
:::

```{.r .cell-code}
plot(gg_vcls) +
  labs(title = "Effect of vehicle class (Body model)",
       x = "Vehicle Class", y = "Predicted Cost (CHF)") +
  scale_y_continuous(labels = scales::label_number(prefix = "CHF ", big.mark = ",")) +
  theme_allianz()
```

