### Regression Table (sjPlot)


::: {.cell}

```{.r .cell-code}
tbl_body  <- tbl_regression(m_body,  exponentiate = TRUE, label = list(
  vehicle_class  ~ "Vehicle Class",
  vehicle_age    ~ "Vehicle Age",
  severity_score ~ "Severity Score",
  region         ~ "Region"
)) |> bold_p(t = 0.05) |> bold_labels()

tbl_glass <- tbl_regression(models_by_type[["glass"]], exponentiate = TRUE, label = list(
  vehicle_class  ~ "Vehicle Class",
  vehicle_age    ~ "Vehicle Age",
  severity_score ~ "Severity Score",
  region         ~ "Region"
)) |> bold_p(t = 0.05) |> bold_labels()

tbl_merge(
  list(tbl_body, tbl_glass),
  tab_spanner = c("**Body Damage (Gamma GLM)**", "**Glass (Gamma GLM)**")
) |>
  modify_caption("**Regression results** · Exponentiated coefficients (cost ratios)") |>
  as_gt() |>
  tab_style(
    style = cell_fill(color = "#003781"),
    locations = cells_column_labels()
  ) |>
  tab_style(
    style = list(cell_text(color = "white", weight = "bold")),
    locations = cells_column_labels()
  ) |>
  tab_options(table.font.size = px(12))
```

