## Observed vs. Expected (O/E) Ratios


::: {.cell}

```{.r .cell-code}
# Use combined model (all types pooled) for O/E
m_combined <- glm(
  repair_cost ~ claim_type + vehicle_class + vehicle_age + severity_score + region,
  data   = claims_steered,
  family = Gamma(link = "log")
)

oe_df_raw <- observed_vs_expected(m_combined, claims_steered)
oe_df     <- oe_df_raw |>
  left_join(partners |> select(partner_id, name, type, region), by = "partner_id")

# Bootstrap CIs for O/E ratios using mirai (1000 resamples)
cat("Bootstrapping O/E CIs with mirai (500 resamples)...\n")
```

::: {.cell-output .cell-output-stdout}

```
Bootstrapping O/E CIs with mirai (500 resamples)...
```


:::

```{.r .cell-code}
daemons(4)

boot_results <- mirai_map(
  seq_len(500L),
  function(b, data, partner_ids) {
    idx   <- sample(nrow(data), nrow(data), replace = TRUE)
    d_boot <- data[idx, ]
    m_boot <- glm(
      repair_cost ~ claim_type + vehicle_class + vehicle_age + severity_score + region,
      data = d_boot, family = Gamma(link = "log")
    )
    d_boot$exp_cost <- predict(m_boot, type = "response")
    tapply(seq_len(nrow(d_boot)), d_boot$partner_id, function(i) {
      sum(d_boot$repair_cost[i]) / sum(d_boot$exp_cost[i])
    })
  },
  .args = list(data = claims_steered, partner_ids = oe_df$partner_id)
)

# Extract CI from bootstrap distribution
boot_mat <- do.call(rbind, lapply(boot_results[], function(x) {
  v <- unlist(x)
  v[oe_df$partner_id]
}))

oe_ci <- apply(boot_mat, 2, function(x) quantile(x, c(0.025, 0.975), na.rm = TRUE))
oe_df <- oe_df |>
  mutate(
    oe_boot_lower = oe_ci[1, ],
    oe_boot_upper = oe_ci[2, ]
  )
daemons(0)
```
