## Partner League Table


::: {.cell}

```{.r .cell-code}
kpis        <- compute_kpis(claims, partners)
kpis_cost   <- cost_benchmark(kpis)
speed_df    <- speed_benchmark(claims, partners)
kpis_qual   <- quality_index(kpis_cost)
kpis_full   <- composite_score(kpis_qual, speed_df)

league_tbl <- kpis_full |>
  left_join(oe_df |> select(partner_id, oe_ratio), by = "partner_id") |>
  left_join(ranef_df |> select(partner_id, shrunk_oe), by = "partner_id") |>
  select(name, type, region, n_claims, avg_cost, oe_ratio, shrunk_oe,
         avg_duration, avg_csat, reopen_rate, composite) |>
  arrange(desc(composite))

league_tbl |>
  slice_head(n = 20) |>
  gt() |>
  tab_header(title = "Top 20 Partners — Adjusted League Table",
             subtitle = "Sorted by composite score") |>
  fmt_number(columns = c(avg_cost), decimals = 0, sep_mark = ",") |>
  fmt_number(columns = c(oe_ratio, shrunk_oe), decimals = 3) |>
  fmt_number(columns = c(avg_duration), decimals = 1) |>
  fmt_number(columns = c(avg_csat), decimals = 2) |>
  fmt_percent(columns = reopen_rate, decimals = 1) |>
  fmt_number(columns = composite, decimals = 1) |>
  data_color(
    columns = composite,
    palette = c("#FF6600", "#66B5E8", "#003781")
  ) |>
  tab_style(
    style = cell_fill(color = "#003781"),
    locations = cells_column_labels()
  ) |>
  tab_style(
    style = list(cell_text(color = "white", weight = "bold")),
    locations = cells_column_labels()
  ) |>
  tab_options(table.font.size = px(12))
